
.location-map {
  position: relative;
  cursor: pointer;
  user-select: none;
  flex-shrink: 0;
}

.map-card {
  position: relative;
  overflow: hidden;
  border-radius: 18px;
  background: #fffef2;
  border: 1px solid rgba(0, 0, 0, 0.08);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.04);
  transition:
    width 0.5s cubic-bezier(0.4, 0, 0.2, 1),
    height 0.5s cubic-bezier(0.4, 0, 0.2, 1),
    transform 0.15s ease-out;
  transform-style: preserve-3d;
}

.is-hovered .map-card {
  border-color: rgba(234, 179, 8, 0.3);
  box-shadow: 0 6px 24px rgba(234, 179, 8, 0.08);
}

.is-expanded .map-card {
  border-color: rgba(234, 179, 8, 0.2);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.06);
}

.card-bg {
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(234, 179, 8, 0.03), transparent 50%, rgba(234, 179, 8, 0.05));
}

/* ===== 地图详情 ===== */
.map-detail {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.map-base {
  position: absolute;
  inset: 0;
  background: rgba(234, 179, 8, 0.02);
}

.map-roads {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
}

/* ---- 路网动画 ---- */
.road {
  stroke-dasharray: 1000;
  stroke-dashoffset: 1000;
}

.is-expanded .road {
  animation: draw-road 1s ease-out forwards;
}

@keyframes draw-road {
  to { stroke-dashoffset: 0; }
}

/* 路网颜色 */
.r-main-h { stroke: rgba(0, 0, 0, 0.18); }
.r-main-v { stroke: rgba(0, 0, 0, 0.14); }
.r-side-h,
.r-side-v { stroke: rgba(0, 0, 0, 0.06); }

/* ---- 地点标注 ---- */
.place-dot {
  fill: rgba(0, 0, 0, 0.12);
  stroke: #fffef2;
  stroke-width: 0.5;
  opacity: 0;
}

.is-expanded .place-dot {
  animation: pop-dot 0.4s ease-out forwards;
}

.place-label {
  font-size: 8px;
  font-weight: 700;
  fill: #1c1c1e;
  opacity: 0;
  pointer-events: none;
}

.is-expanded .place-label {
  animation: fade-in 0.4s ease-out forwards;
}

@keyframes pop-dot {
  from { opacity: 0; r: 0; }
  to { opacity: 1; }
}
@keyframes fade-in { to { opacity: 1; } }

/* ---- 建筑区块 ---- */
.building {
  position: absolute;
  border-radius: 2px;
  background: rgba(0, 0, 0, 0.04);
  border: 1px solid rgba(0, 0, 0, 0.06);
  opacity: 0;
  transform: scale(0.8);
}

.is-expanded .building {
  animation: build-rise 0.5s ease-out forwards;
}

@keyframes build-rise {
  from { opacity: 0; transform: scale(0.8); }
  to { opacity: 1; transform: scale(1); }
}

/* ---- 中心定位点 ---- */
.center-pin {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  opacity: 0;
  z-index: 5;
}

.is-expanded .center-pin {
  animation: pin-spring 0.6s cubic-bezier(0.34, 1.56, 0.64, 1) 0.3s forwards;
}

@keyframes pin-spring {
  from {
    opacity: 0;
    transform: translate(-50%, -50%) scale(0) translateY(-20px);
  }
  to {
    opacity: 1;
    transform: translate(-50%, -50%) scale(1) translateY(0);
  }
}

.pin-svg {
  filter: drop-shadow(0 0 10px rgba(234, 179, 8, 0.5));
}

.pin-inner { fill: #fffef2; }

/* ---- 底部渐变 ---- */
.map-bottom-fade {
  position: absolute;
  inset: auto 0 0 0;
  height: 30%;
  background: linear-gradient(to top, rgba(255, 254, 242, 0.7), transparent);
  pointer-events: none;
}

/* ===== 网格纹理 ===== */
.card-grid {
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(0, 0, 0, 0.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0, 0, 0, 0.03) 1px, transparent 1px);
  background-size: 15px 15px;
  transition: opacity 0.35s;
}

/* ===== 内容 ===== */
.card-content {
  position: relative;
  z-index: 10;
  height: 100%;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  padding: 18px 20px;
}

.card-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.map-icon {
  transition: filter 0.3s;
}

.is-hovered .map-icon {
  filter: drop-shadow(0 0 6px rgba(234, 179, 8, 0.5));
}

.live-tag {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 9px;
  border-radius: 10px;
  font-size: 14px;
  font-weight: 700;
  color: #8e8e93;
  background: rgba(0, 0, 0, 0.03);
  letter-spacing: 0.8px;
  transition: all 0.2s;
}

.is-hovered .live-tag {
  background: rgba(234, 179, 8, 0.08);
  transform: scale(1.05);
}

.live-dot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: #eab308;
}

.card-bottom {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.location-name {
  font-size: 18px;
  font-weight: 800;
  color: #1c1c1e;
  transition: transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
  line-height: 1.2;
}

.is-hovered .location-name {
  transform: translateX(4px);
}

.location-weather {
  font-size: 15px;
  color: #8e8e93;
  font-weight: 600;
}

.card-underline {
  height: 2px;
  background: linear-gradient(90deg, rgba(234, 179, 8, 0.5), rgba(234, 179, 8, 0.2), transparent);
  transform-origin: left;
  transform: scaleX(0.3);
  transition: transform 0.4s ease;
}

.is-hovered .card-underline,
.is-expanded .card-underline {
  transform: scaleX(1);
}

.click-hint {
  position: absolute;
  bottom: -24px;
  left: 50%;
  transform: translateX(-50%);
  font-size: 14px;
  color: #8e8e93;
  white-space: nowrap;
  font-weight: 600;
}

/* ===== 暗色模式 ===== */
.map-dark .map-card {
  background: #1c1c1e;
  border-color: rgba(255, 255, 255, 0.08);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.3);
}

.map-dark.is-hovered .map-card {
  border-color: rgba(234, 179, 8, 0.3);
  box-shadow: 0 6px 24px rgba(234, 179, 8, 0.12);
}

.map-dark.is-expanded .map-card {
  background: #1c1c1e;
  border-color: rgba(234, 179, 8, 0.25);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
}

.map-dark .card-bg {
  background: linear-gradient(135deg, rgba(234, 179, 8, 0.04), transparent 50%, rgba(234, 179, 8, 0.06));
}

.map-dark .map-base {
  background: rgba(234, 179, 8, 0.03);
}

.map-dark .location-name { color: #f5f5f7; }
.map-dark .location-weather { color: #98989d; }
.map-dark .click-hint { color: #98989d; }
.map-dark .live-tag { color: #98989d; background: rgba(255, 255, 255, 0.04); }
.map-dark .place-label { fill: #f5f5f7; }
.map-dark .place-dot {
  fill: rgba(255, 255, 255, 0.18);
  stroke: #2c2c2e;
}
.map-dark .pin-inner { fill: #1c1c1e; }
.map-dark .map-bottom-fade {
  background: linear-gradient(to top, rgba(28, 28, 30, 0.7), transparent);
}
.map-dark .card-grid {
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.03) 1px, transparent 1px);
}
.map-dark .road { stroke: rgba(255, 255, 255, 0.05); }
.map-dark .r-main-h { stroke: rgba(255, 255, 255, 0.18); }
.map-dark .r-main-v { stroke: rgba(255, 255, 255, 0.14); }
.map-dark .r-side-h,
.map-dark .r-side-v { stroke: rgba(255, 255, 255, 0.06); }
.map-dark .building {
  background: rgba(255, 255, 255, 0.04);
  border-color: rgba(255, 255, 255, 0.06);
}

/* ===== 过渡动画 ===== */
.map-detail-enter-active {
  transition: opacity 0.35s ease;
}
.map-detail-leave-active {
  transition: opacity 0.2s ease;
}
.map-detail-enter-from,
.map-detail-leave-to {
  opacity: 0;
}

.map-fade-enter-active { transition: opacity 0.35s ease; }
.map-fade-leave-active { transition: opacity 0.2s ease; }
.map-fade-enter-from,
.map-fade-leave-to { opacity: 0; }

.hint-fade-enter-active {
  transition: opacity 0.2s ease, transform 0.2s ease;
}
.hint-fade-leave-active {
  transition: opacity 0.15s ease;
}
.hint-fade-enter-from {
  opacity: 0;
  transform: translate(-50%, 4px);
}
.hint-fade-leave-to {
  opacity: 0;
}
